'use strict';
/**
 * REGRESSION — FRG-184
 * Verifies that characters move via A* pathfinding (action = 'walking',
 * tile coordinates change over time).
 */
const { test, expect } = require('@playwright/test');
const { waitForEngine, getEngineState, pollEngineState } = require('../helpers');

test.describe('Regression: Character movement via A*', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/');
    await waitForEngine(page);
  });

  test('at least one character enters walking state within 15 seconds', async ({ page }) => {
    const finalState = await pollEngineState(
      page,
      state => state.characters.some(c => c.action === 'walking'),
      15_000
    );
    const walking = finalState.characters.filter(c => c.action === 'walking');
    expect(walking.length).toBeGreaterThanOrEqual(1);
  });

  test('walking character tile position changes over time', async ({ page }) => {
    // Wait until someone walks
    const state1 = await pollEngineState(
      page,
      state => state.characters.some(c => c.action === 'walking'),
      15_000
    );

    const walker = state1.characters.find(c => c.action === 'walking');
    const startTx = walker.tx;
    const startTy = walker.ty;

    // Wait for movement to complete
    await page.waitForTimeout(6000);
    const state2 = await getEngineState(page);
    const walkerAfter = state2.characters.find(c => c.name === walker.name);

    // Position must have changed
    const moved = walkerAfter.tx !== startTx || walkerAfter.ty !== startTy;
    expect(moved, `${walker.label} did not move from (${startTx}, ${startTy})`).toBe(true);
  });

  test('characters stay within walkable bounds (cols 1–17, rows 2–9)', async ({ page }) => {
    // Sample character positions over 10 seconds
    for (let i = 0; i < 5; i++) {
      await page.waitForTimeout(2000);
      const state = await getEngineState(page);
      for (const c of state.characters) {
        expect(c.tx, `${c.label} x=${c.tx} out of bounds`).toBeGreaterThanOrEqual(1);
        expect(c.tx, `${c.label} x=${c.tx} out of bounds`).toBeLessThanOrEqual(17);
        expect(c.ty, `${c.label} y=${c.ty} out of bounds`).toBeGreaterThanOrEqual(2);
        expect(c.ty, `${c.label} y=${c.ty} out of bounds`).toBeLessThanOrEqual(9);
      }
    }
  });

  test('character action transitions: idle → walking → idle', async ({ page }) => {
    // Observe a character through a full walk cycle
    const walkStartState = await pollEngineState(
      page,
      state => state.characters.some(c => c.action === 'walking'),
      15_000
    );
    const charName = walkStartState.characters.find(c => c.action === 'walking').name;

    // Wait for that character to return to idle
    const idleState = await pollEngineState(
      page,
      state => state.characters.find(c => c.name === charName)?.action === 'idle',
      20_000
    );
    const charIdle = idleState.characters.find(c => c.name === charName);
    expect(charIdle.action).toBe('idle');
  });
});

