'use strict';
/**
 * REGRESSION — FRG-184
 * Verifies that object state changes are visible and that interactions
 * (both random-wander and AI-triggered) work correctly.
 *
 * Also captures the known bug: AIEngine uses `_pendingInteract` but
 * SimulationEngine._handleObjectArrival checks `targetObjectId`, so
 * AI-driven interactions never fire object state transitions.
 */
const { test, expect } = require('@playwright/test');
const { waitForEngine, getEngineState, pollEngineState } = require('../helpers');

test.describe('Regression: Object interaction and state changes', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('/');
    await waitForEngine(page);
  });

  test('at least one object changes state within 60 seconds', async ({ page }) => {
    const initial = await getEngineState(page);
    const initialMap = Object.fromEntries(initial.objectStates.map(o => [o.id, o.state]));

    const changed = await pollEngineState(
      page,
      state => state.objectStates.some(o => o.state !== initialMap[o.id]),
      60_000,
      1000
    );

    const changedObjects = changed.objectStates.filter(o => o.state !== initialMap[o.id]);
    expect(changedObjects.length).toBeGreaterThanOrEqual(1);
    console.log('Objects that changed state:', changedObjects.map(o => `${o.id}: ${initialMap[o.id]} → ${o.state}`).join(', '));
  });

  test('debug panel reflects live object state changes', async ({ page }) => {
    // Open debug panel
    await page.getByRole('button', { name: /debug/i }).click();

    // Wait for an object to go non-idle
    const changed = await pollEngineState(
      page,
      state => state.objectStates.some(o => o.state !== 'idle'),
      60_000,
      1000
    );

    const nonIdle = changed.objectStates.find(o => o.state !== 'idle');
    expect(nonIdle).toBeTruthy();

    // The debug panel should reflect the new state
    const stateText = page.getByText(nonIdle.state, { exact: false });
    await expect(stateText).toBeVisible({ timeout: 5000 });
  });

  test('debug panel "use" button triggers object state change', async ({ page }) => {
    await page.getByRole('button', { name: /debug/i }).click();

    const initial = await getEngineState(page);
    const idleObject = initial.objectStates.find(o => o.state === 'idle');
    expect(idleObject, 'Need at least one idle object').toBeTruthy();

    // Find and click the "use" button for that object
    // The debug panel rows are: ObjectName | stateLabel | useButton
    const objectLabel = idleObject.label;
    const row = page.locator(`text=${objectLabel}`).locator('..').first();
    const useBtn = row.getByRole('button', { name: /use/i });

    // Fall back: just find any use button
    const anyUseBtn = page.getByRole('button', { name: 'use' }).first();
    await anyUseBtn.click();

    // State should change
    await page.waitForTimeout(500);
    const after = await getEngineState(page);
    const anyNonIdle = after.objectStates.some(o => o.state !== 'idle');
    expect(anyNonIdle, 'No object changed state after clicking "use"').toBe(true);
  });

  test('object auto-transitions back to idle after timed duration', async ({ page }) => {
    // Target the bonsai specifically: auto_next = 12 real seconds (fastest cycle)
    // Test timeout extended to allow the full cycle
    test.setTimeout(120_000);

    await page.getByRole('button', { name: /debug/i }).click();

    // Directly trigger bonsai via engine (avoids DOM layout uncertainty)
    await page.evaluate(() => {
      window._gameEngine.objectEngine.interact('bonsai', 'use');
    });

    // Confirm bonsai is now in 'tending'
    await page.waitForTimeout(500);
    const activated = await getEngineState(page);
    const bonsai = activated.objectStates.find(o => o.id === 'bonsai');
    expect(bonsai?.state, 'Bonsai should be in tending state').toBe('tending');

    console.log('Bonsai transitioned to tending, waiting for auto-return to idle (12s)...');

    // Wait for bonsai auto_next: idle after 12 real seconds
    const returned = await pollEngineState(
      page,
      state => state.objectStates.find(o => o.id === 'bonsai')?.state === 'idle',
      30_000,
      500
    );
    const bonsaiAfter = returned.objectStates.find(o => o.id === 'bonsai');
    expect(bonsaiAfter.state).toBe('idle');
  });

  // ── BUG DOCUMENTATION TEST ────────────────────────────────────────────────
  test('[BUG] AI interact decision sets _pendingInteract but engine checks targetObjectId', async ({ page }) => {
    // This test documents the known bug:
    // AIEngine._applyDecision sets character._pendingInteract = obj.id
    // SimulationEngine._handleObjectArrival checks char.targetObjectId (never set by AI)
    // Result: AI-driven "interact" decisions do NOT trigger object state changes.

    const interactDecisions = [];
    page.on('response', async res => {
      if (res.url().includes('/api/llm')) {
        try {
          const json = await res.json();
          const text = json?.content?.[0]?.text ?? json?.choices?.[0]?.message?.content;
          if (text) {
            const d = JSON.parse(text);
            if (d.action === 'interact') interactDecisions.push(d);
          }
        } catch { /* ignore */ }
      }
    });

    await page.goto('/');
    await waitForEngine(page);
    await page.waitForTimeout(10000); // capture initial decisions

    if (interactDecisions.length === 0) {
      // No interact decisions in this run — test is inconclusive, skip gracefully
      console.log('[BUG test] No "interact" decisions captured in this run, skipping verification');
      return;
    }

    // Verify: after an AI "interact" decision, check if _pendingInteract is set
    // and if targetObjectId is NOT set (confirming the bug)
    const bugCheck = await page.evaluate(() => {
      const chars = window._gameEngine?.characters ?? [];
      return chars.map(c => ({
        name: c.name,
        hasPendingInteract: '_pendingInteract' in c && c._pendingInteract !== undefined,
        hasTargetObjectId: c.targetObjectId !== null && c.targetObjectId !== undefined,
        pendingInteract: c._pendingInteract,
        targetObjectId: c.targetObjectId,
      }));
    });

    console.log('[BUG] Character interact state:', JSON.stringify(bugCheck, null, 2));

    // Document: at least one character with _pendingInteract should lack targetObjectId
    // This confirms the mismatch
    const bugged = bugCheck.filter(c => c.hasPendingInteract && !c.hasTargetObjectId);
    if (bugged.length > 0) {
      console.warn(`[BUG CONFIRMED] ${bugged.length} character(s) have _pendingInteract set but targetObjectId is null — AI interact decisions will not trigger object state changes`);
    }

    // The test itself passes (it's documenting, not blocking) — the regression
    // suite will catch when this is fixed by expecting AI-triggered state changes.
    expect(interactDecisions.length).toBeGreaterThanOrEqual(1); // we got interact decisions
  });
});

