'use strict';
const { test } = require('@playwright/test');
const { waitForEngine, pollEngineState } = require('../helpers');

test('probe: AI interval and character interaction timer', async ({ page }) => {
  test.setTimeout(90000);
  const requests = [];
  page.on('request', req => {
    if (req.url().includes('/api/llm') && req.method() === 'POST') {
      requests.push({ url: req.url(), ts: Date.now() });
    }
  });

  await page.goto('/');
  await waitForEngine(page);

  const aiInterval = await page.evaluate(() => window._gameEngine.aiEngine.decisionIntervalMs);
  console.log('AI decisionIntervalMs:', aiInterval);

  // Wait for 2 rounds of decisions (> 30s)
  await page.waitForTimeout(40000);

  // Check timings
  console.log('Total LLM requests:', requests.length);
  if (requests.length > 3) {
    // Group by approximate 30s windows
    const firstGroup = requests.filter(r => r.ts - requests[0].ts < 5000);
    const secondGroup = requests.filter(r => r.ts - requests[0].ts >= 25000 && r.ts - requests[0].ts <= 45000);
    console.log('First batch (0-5s):', firstGroup.length);
    console.log('Second batch (25-45s):', secondGroup.length);
  }

  // Check interaction timer
  const charState = await page.evaluate(() =>
    window._gameEngine.characters.map(c => ({
      label: c.label,
      action: c.action,
      interactTimer: c.interactTimer,
      interactTimerMax: c.interactTimerMax,
      targetObjectId: c.targetObjectId,
      pendingAction: c.pendingAction,
    }))
  );
  console.log('Character states after 40s:', JSON.stringify(charState, null, 2));

  // Check all action types seen
  const allActions = new Set();
  for (let i = 0; i < 5; i++) {
    const s = await page.evaluate(() => window._gameEngine.characters.map(c => c.action));
    s.forEach(a => allActions.add(a));
    await page.waitForTimeout(2000);
  }
  console.log('Action types observed:', [...allActions]);

  // Check what "Full dashboard" link leads to
  const dashLink = await page.evaluate(() => {
    const links = Array.from(document.querySelectorAll('a'));
    return links.map(l => ({ text: l.textContent, href: l.href }));
  });
  console.log('All links:', JSON.stringify(dashLink, null, 2));
});
